// Generated from data/traps.json by scripts/generate-trap-bindings.mjs.
// Each binding pairs a typed APNs error class name with the trap id it
// surfaces. The catalog is the source of truth; do not edit this file by
// hand. Run pnpm surface:check (which calls --check) to verify drift; run
// node --experimental-strip-types scripts/generate-trap-bindings.mjs to
// regenerate after editing data/traps.json.

export const TRAP_ID_BY_ERROR_CLASS = {
  BadDeviceTokenError: "MS014",
  MissingApnsConfigError: "MS028",
  PayloadTooLargeError: "MS011",
  TooManyRequestsError: "MS015",
  TopicDisallowedError: "MS018",
} as const satisfies Record<string, `MS${string}`>;

export type TrapBoundErrorClassName = keyof typeof TRAP_ID_BY_ERROR_CLASS;

/**
 * Look up the trap id for a given error class name. Returns undefined for
 * classes that have no catalog entry (most SDK-self-correctness errors).
 * Consumers should treat the result as opaque metadata for log aggregation
 * or doc-link rendering; the trap catalog is the canonical source of fix
 * instructions.
 */
export function trapIdForErrorClass(className: string): string | undefined {
  return (TRAP_ID_BY_ERROR_CLASS as Record<string, string>)[className];
}
